import torch
def rot_trans_geo(geometry, rot, trans):
    import torch
    def rot_trans_geo(geometry, rot, trans):
        geometry = geometry.transpose(1, 2)
        rott_geo = torch.bmm(rot, geometry) + trans.unsqueeze(-1)
        return rott_geo.transpose(1, 2)

