import torch
def rot_trans_geo(geometry, rot, trans):
    import torch
    def rot_trans_geo(geometry, rot, trans):
        rott_geo = torch.matmul(rot, geometry.permute(0, 2, 1)) + trans.view(-1, 3, 1)
        return rott_geo.transpose(0, 2, 1)

