import torch
def rot_trans_geo(geometry, rot, trans):
    import torch
    def rot_trans_geo(geometry, rot, trans):
        rott_geo = torch.einsum('bik,bkj->bij', (rot, geometry)) + trans.unsqueeze(-1)
        return rott_geo.transpose(1, 2)

